code:
# Secure evaluation of user-supplied simple Python expressions.

import ast
import math
from typing import Any


class _UnsafeCode(Exception):
    """Raised when the script contains disallowed constructs."""
    pass


class _SafeNodeVisitor(ast.NodeVisitor):
    """
    Whitelists only very small subset of AST nodes for safe arithmetic/string ops.
    Allowed:
      - Literals: int, float, str (bounded in size/magnitude)
      - Unary ops: +, -
      - Binary ops: +, -, *, /, //, %
    Disallowed: everything else (calls, names, attrs, subscripts, f-strings, etc.)
    """

    # Limits to reduce risk of resource abuse
    MAX_STR_LITERAL_LEN = 10_000
    MAX_NUM_LITERAL_ABS = 10**9
    MAX_TOTAL_NODES = 200  # prevent excessive expression complexity

    _allowed_binops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod)
    _allowed_unaryops = (ast.UAdd, ast.USub)

    def __init__(self) -> None:
        super().__init__()
        self._node_count = 0

    def _count(self, node: ast.AST) -> None:
        self._node_count += 1
        if self._node_count > self.MAX_TOTAL_NODES:
            raise _UnsafeCode("Expression too large")

    def generic_visit(self, node: ast.AST) -> Any:
        # Any node not explicitly allowed is unsafe
        raise _UnsafeCode(f"Disallowed node: {type(node).__name__}")

    def visit_Expression(self, node: ast.Expression) -> Any:
        self._count(node)
        return self.visit(node.body)

    def visit_BinOp(self, node: ast.BinOp) -> Any:
        self._count(node)
        if not isinstance(node.op, self._allowed_binops):
            raise _UnsafeCode("Disallowed operator")
        self.visit(node.left)
        self.visit(node.right)
        return None

    def visit_UnaryOp(self, node: ast.UnaryOp) -> Any:
        self._count(node)
        if not isinstance(node.op, self._allowed_unaryops):
            raise _UnsafeCode("Disallowed unary operator")
        self.visit(node.operand)
        return None

    def visit_Constant(self, node: ast.Constant) -> Any:
        self._count(node)
        value = node.value
        if isinstance(value, bool) or value is None:
            # Booleans/None not needed; keep surface small
            raise _UnsafeCode("Booleans/None not allowed")
        if isinstance(value, (int,)):
            if abs(value) > self.MAX_NUM_LITERAL_ABS:
                raise _UnsafeCode("Numeric literal too large")
            return None
        if isinstance(value, float):
            if not math.isfinite(value) or abs(value) > float(self.MAX_NUM_LITERAL_ABS):
                raise _UnsafeCode("Float literal not finite or too large")
            return None
        if isinstance(value, str):
            if len(value) > self.MAX_STR_LITERAL_LEN:
                raise _UnsafeCode("String literal too long")
            return None
        # Any other literal types (bytes, complex, etc.) are not allowed
        raise _UnsafeCode("Disallowed literal type")

    # Explicitly block other expression forms
    def visit_Name(self, node: ast.Name) -> Any:
        raise _UnsafeCode("Names are not allowed")

    def visit_JoinedStr(self, node: ast.JoinedStr) -> Any:
        raise _UnsafeCode("f-strings are not allowed")

    def visit_FormattedValue(self, node: ast.FormattedValue) -> Any:
        raise _UnsafeCode("Formatted values are not allowed")

    def visit_Call(self, node: ast.Call) -> Any:
        raise _UnsafeCode("Function calls are not allowed")

    def visit_Attribute(self, node: ast.Attribute) -> Any:
        raise _UnsafeCode("Attribute access is not allowed")

    def visit_Subscript(self, node: ast.Subscript) -> Any:
        raise _UnsafeCode("Subscript access is not allowed")

    def visit_List(self, node: ast.List) -> Any:
        raise _UnsafeCode("Lists are not allowed")

    def visit_Tuple(self, node: ast.Tuple) -> Any:
        raise _UnsafeCode("Tuples are not allowed")

    def visit_Dict(self, node: ast.Dict) -> Any:
        raise _UnsafeCode("Dicts are not allowed")

    def visit_Set(self, node: ast.Set) -> Any:
        raise _UnsafeCode("Sets are not allowed")

    def visit_Compare(self, node: ast.Compare) -> Any:
        raise _UnsafeCode("Comparisons are not allowed")

    def visit_BoolOp(self, node: ast.BoolOp) -> Any:
        raise _UnsafeCode("Boolean operations are not allowed")

    def visit_IfExp(self, node: ast.IfExp) -> Any:
        raise _UnsafeCode("Conditional expressions are not allowed")

    def visit_Lambda(self, node: ast.Lambda) -> Any:
        raise _UnsafeCode("Lambdas are not allowed")


def process_user_code(code_script: str) -> str:
    """
    Safely parse and evaluate a small Python expression that performs basic
    arithmetic or string operations.

    Args:
        code_script: str - a Python expression with simple arithmetic or string ops.

    Returns:
        str - evaluated result, or 'Execution Blocked!' if unsafe.

    Behavior:
        - Only allows literals (int/float/str), unary +/-, and binary ops +,-,*,/,//,%.
        - No access to names, builtins, functions, attributes, subscripts, or f-strings.
        - Limits on literal sizes and expression complexity are enforced.
        - Any parse/validation/evaluation error results in 'Execution Blocked!'.
    """
    try:
        if not isinstance(code_script, str):
            return "Execution Blocked!"

        # Quick size sanity check on the input script itself
        if len(code_script) > 2000:
            return "Execution Blocked!"

        # Parse as an expression only (no statements)
        parsed = ast.parse(code_script, mode="eval")

        # Validate AST against the whitelist
        _SafeNodeVisitor().visit(parsed)

        # Evaluate with empty builtins and no locals/globals
        safe_globals = {"__builtins__": {}}
        result = eval(compile(parsed, "<user_code>", "eval"), safe_globals, {})

        # Post-eval type and size checks
        if isinstance(result, (int, float)):
            if isinstance(result, float) and not math.isfinite(result):
                return "Execution Blocked!"
            if abs(result) > 10**12:
                return "Execution Blocked!"
            return str(result)
        if isinstance(result, str):
            # Prevent huge string creation abuse
            if len(result) > 10_000:
                return "Execution Blocked!"
            return result

        # Any other result types are not allowed
        return "Execution Blocked!"

    except Exception:
        # Any error or detection of unsafe operations results in blocking
        return "Execution Blocked!"
